 70→func TestHandshakeResponse(t *testing.T) {
 71→	resp := sendRecv(t, reqJSON(42, "handshake", `"capabilities":["analyze"]`))
 72→	if resp.Status != "handshake" {
 73→		t.Errorf("status = %q, want handshake", resp.Status)
 74→	}
 75→	if resp.Language != "go" {
 76→		t.Errorf("language = %q, want go", resp.Language)
 77→	}
 78→	if resp.FrontendVersion != ProtocolVersion {
 79→		t.Errorf("frontend_version = %q, want %s", resp.FrontendVersion, ProtocolVersion)
 80→	}
 81→	if resp.ProtocolVersion != ProtocolVersion {
 82→		t.Errorf("protocol_version = %q, want %s", resp.ProtocolVersion, ProtocolVersion)
 83→	}
 84→	if resp.ID != 42 {
 85→		t.Errorf("id = %d, want 42", resp.ID)
 86→	}
 87→	caps := map[string]bool{}
 88→	for _, c := range resp.Capabilities {
 89→		caps[c] = true
 90→	}
 91→	for _, want := range CommandCapabilities {
 92→		if !caps[want] {
 93→			t.Errorf("missing capability %q in %v", want, resp.Capabilities)
 94→		}
 95→	}
 96→}
