229→// TestPropertyHandlerResponseOrdering verifies that for any sequence of valid
230→// requests, the handler produces responses with matching IDs in the same order
231→// (no reordering, no drops). Shutdown terminates processing.
232→func TestPropertyHandlerResponseOrdering(t *testing.T) {
233→	rapid.Check(t, func(t *rapid.T) {
234→		// Generate 1-5 non-shutdown commands followed by shutdown
235→		n := rapid.IntRange(1, 5).Draw(t, "numCommands")
236→		var lines []string
237→		var expectedIDs []int
238→
239→		for i := 0; i < n; i++ {
240→			cmd := genNonShutdownCommand().Draw(t, fmt.Sprintf("cmd%d", i))
241→			line := fmt.Sprintf(`{"protocol_version":%q,"id":%d,"command":%q}`, ProtocolVersion, i+1, cmd)
242→			lines = append(lines, line)
243→			expectedIDs = append(expectedIDs, i+1)
244→		}
245→		// Append shutdown
246→		shutdownID := n + 1
247→		lines = append(lines, fmt.Sprintf(`{"protocol_version":%q,"id":%d,"command":"shutdown"}`, ProtocolVersion, shutdownID))
248→		expectedIDs = append(expectedIDs, shutdownID)
249→
250→		input := strings.Join(lines, "\n") + "\n"
251→		var out bytes.Buffer
252→		h := NewHandlerWithLogLevel(strings.NewReader(input), &out, &bytes.Buffer{}, "error")
253→
254→		if err := h.Run(); err != nil {
255→			t.Fatalf("handler.Run(): %v", err)
256→		}
257→
258→		// Parse responses
259→		scanner := bufio.NewScanner(&out)
260→		var gotIDs []int
261→		for scanner.Scan() {
262→			var resp Response
263→			if err := json.Unmarshal(scanner.Bytes(), &resp); err != nil {
264→				t.Fatalf("unmarshal response: %v", err)
265→			}
266→			gotIDs = append(gotIDs, resp.ID)
267→		}
268→
269→		if len(gotIDs) != len(expectedIDs) {
270→			t.Fatalf("response count: got %d, want %d", len(gotIDs), len(expectedIDs))
271→		}
272→		for i := range expectedIDs {
273→			if gotIDs[i] != expectedIDs[i] {
274→				t.Fatalf("response[%d] ID: got %d, want %d", i, gotIDs[i], expectedIDs[i])
275→			}
276→		}
277→	})
